def plan_customization() -> any:
    from smolagents import CodeAgent
    agent = CodeAgent()

    def interrupt_after_plan_callback(plan, step_type):
        if step_type != 'plan':
            return
        print('Generated plan:')
        for i, step in enumerate(plan, 1):
            print(f'{i}. {step}')
        while True:
            choice = input('Approve (a), Modify (m), Cancel (c): ').strip().lower()
            if choice == 'a':
                return
            elif choice == 'm':
                new_plan = input('Enter modified plan (comma-separated steps): ').strip()
                if new_plan:
                    return new_plan.split(',')
                else:
                    print('Invalid input, try again')
            elif choice == 'c':
                agent.interrupt()
                raise KeyboardInterrupt('Execution cancelled by user')
            else:
                print('Invalid choice, try again')

    agent.step_callbacks['after_plan'] = interrupt_after_plan_callback
    try:
        result = agent.run()
    except KeyboardInterrupt:
        print('Execution cancelled. Resuming...')
        resumed_result = agent.run(reset=False)
        return resumed_result
    return result
